// site/flash-manifest.js — DOM-free validation for the Fresh-install path's
// manifest.json shape (site/flash.js's runFreshFlash). Pulled out for the
// same reason site/upgrade-gate.js was: the decision of which bytes get
// written to which flash address is safety-critical (a wrong offset can
// brick a device), so it gets plain-node test coverage independent of a
// browser/DOM — see upgrade-gate.js's own header for the precedent.
//
// manifest.json is generated by .github/workflows/release.yml's "Generate
// esp-web-tools manifest.json" step and mirrored same-origin by
// .github/workflows/pages-deploy.yml — see docs/adr/0006-web-flasher.md.
// It happens to be shaped as an esp-web-tools manifest (this project no
// longer depends on esp-web-tools itself — see docs/adr/0011-unified-
// esptool-js-flasher.md — but keeps emitting the same file shape so a user
// who grabs it by hand from GitHub Releases can still feed it to any
// esp-web-tools-compatible flasher). Nothing stops a corrupted mirror or a
// hand-edited release asset from not matching that shape, so this is
// validated the same "fail closed" way isValidUpdateMeta validates
// update-meta.json.

// release.yml's own merged-image naming convention
// (meshcadet-vX.Y.Z-merged.bin). A part path feeds directly into a
// same-origin fetch URL (firmware/<tag>/<path>, flash.js's runFreshFlash);
// constraining its shape rules out a malformed/tampered value escaping the
// intended firmware/<tag>/ directory (e.g. via "../"), mirroring
// upgrade-gate.js's APP_ASSET_RE guard.
const MERGED_ASSET_RE = /^meshcadet-v\d+\.\d+\.\d+-merged\.bin$/;

/**
 * Picks the flashable `{path, offset}` parts for `expectedChipFamily` out of
 * a parsed manifest.json, or returns `null` if the manifest doesn't have the
 * exact shape `runFreshFlash` needs — no matching chip family, no parts, or
 * any part with a malformed path/offset. Mirrors `isValidUpdateMeta`'s
 * fail-closed contract: a malformed/unexpected manifest refuses to guess a
 * flash address rather than writing to whatever `offset` happens to parse.
 */
export function resolveFreshInstallParts(manifest, expectedChipFamily) {
  if (manifest === null || typeof manifest !== "object" || !Array.isArray(manifest.builds)) {
    return null;
  }

  const build = manifest.builds.find(
    (candidate) => candidate !== null && typeof candidate === "object" && candidate.chipFamily === expectedChipFamily
  );
  if (!build || !Array.isArray(build.parts) || build.parts.length === 0) {
    return null;
  }

  const parts = [];
  for (const part of build.parts) {
    if (
      part === null ||
      typeof part !== "object" ||
      typeof part.path !== "string" ||
      !MERGED_ASSET_RE.test(part.path) ||
      !Number.isInteger(part.offset) ||
      part.offset < 0
    ) {
      return null;
    }
    parts.push({ path: part.path, offset: part.offset });
  }
  return parts;
}
